import React, { useState, useEffect } from 'react';
import axios from 'axios';

function App() {
  const [page, setPage] = useState('home'); 
  const [students, setStudents] = useState([]);
  const [formData, setFormData] = useState({
    magaca: '', aqoonsi_id: '', fasalka: '', meesha_dhalashada: '', waalid_tel: ''
  });

  // Soo qaadashada liiska ardayda
  const fetchStudents = () => {
    axios.get('http://localhost:3000/students').then(res => setStudents(res.data));
  };

  useEffect(() => { fetchStudents(); }, []);

  // Kaydinta arday cusub
  const handleSave = async (e) => {
    e.preventDefault();
    await axios.post('http://localhost:3000/add-student', formData);
    alert("Si guul leh ayaa loo kaydiyey!");
    setPage('attendance'); // Markay dhamaato u gudub xaadiriska
    fetchStudents();
  };

  return (
    <div style={{ padding: '20px', fontFamily: 'Arial' }}>
      {/* 1. MENU-GA SARE (Badamada Navigation-ka) */}
      <nav style={styles.navBar}>
        <button onClick={() => setPage('home')} style={styles.btnNav}>🏠 Hoyga</button>
        <button onClick={() => setPage('register')} style={styles.btnNav}>➕ Diiwaangeli</button>
        <button onClick={() => setPage('attendance')} style={styles.btnNav}>📝 Xaadiriska</button>
      </nav>

      {/* 2. BOGGA DIIWAANGELINTA */}
      {page === 'register' && (
        <div style={styles.card}>
          <h3>Foomka Ardayga Cusub</h3>
          <form onSubmit={handleSave}>
            <input style={styles.input} placeholder="Magaca" onChange={e => setFormData({...formData, magaca: e.target.value})} required />
            <input style={styles.input} placeholder="ID-ga Ardayga" onChange={e => setFormData({...formData, aqoonsi_id: e.target.value})} required />
            <input style={styles.input} placeholder="Fasalka" onChange={e => setFormData({...formData, fasalka: e.target.value})} required />
            <input style={styles.input} placeholder="Meesha Dhalashada" onChange={e => setFormData({...formData, meesha_dhalashada: e.target.value})} required />
            <button type="submit" style={styles.btnSave}>💾 Keydi Xogta</button>
          </form>
        </div>
      )}

      {/* 3. BOGGA XAADIRISKA (√ iyo X) */}
      {page === 'attendance' && (
        <div style={styles.card}>
          <h3>Xaadiriska Maanta</h3>
          <table border="0" width="100%" style={{ borderCollapse: 'collapse' }}>
            <thead>
              <tr style={{ background: '#f4f4f4' }}>
                <th style={{ padding: '10px' }}>Ardayga</th>
                <th>Fasalka</th>
                <th>Xaaladda</th>
              </tr>
            </thead>
            <tbody>
              {students.map(std => (
                <tr key={std._id} style={{ borderBottom: '1px solid #eee' }}>
                  <td style={{ padding: '10px' }}>{std.magaca}</td>
                  <td>{std.fasalka}</td>
                  <td>
                    <button style={styles.btnSax} onClick={() => alert("Waa la saaxay √")}>√ Sax</button>
                    <button style={styles.btnQalad} onClick={() => alert("Waa la qalday X")}>X Qalad</button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}
    </div>
  );
}

// QAYBTA QURXINTA (CSS in JS)
const styles = {
  navBar: { display: 'flex', gap: '10px', background: '#2c3e50', padding: '15px', borderRadius: '10px' },
  btnNav: { padding: '10px 20px', cursor: 'pointer', borderRadius: '5px', border: 'none' },
  card: { marginTop: '20px', padding: '20px', border: '1px solid #ddd', borderRadius: '10px' },
  input: { display: 'block', width: '100%', padding: '10px', marginBottom: '10px', borderRadius: '5px', border: '1px solid #ccc' },
  btnSave: { background: '#3498db', color: 'white', padding: '10px 20px', border: 'none', borderRadius: '5px', cursor: 'pointer' },
  btnSax: { background: '#27ae60', color: 'white', border: 'none', padding: '5px 15px', borderRadius: '5px', cursor: 'pointer', marginRight: '5px' },
  btnQalad: { background: '#e74c3c', color: 'white', border: 'none', padding: '5px 15px', borderRadius: '5px', cursor: 'pointer' }
};

export default App;
